class SecureStorage private constructor(context: Context) {

    private val masterKey = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .build()

    private val securePrefs = EncryptedSharedPreferences.create(
        context,
        "secure_payment_prefs",
        masterKey,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    fun storeWalletBalance(userId: String, balance: BigDecimal) {
        val hashedKey = SecurityUtils.hashSensitiveData("balance_$userId")
        val encrypted = SecurityUtils.encrypt(balance.toPlainString())
        securePrefs.edit()
            .putString("${hashedKey}_ct", encrypted.cipherText)
            .putString("${hashedKey}_iv", encrypted.iv)
            .apply()
    }

    fun getWalletBalance(userId: String): BigDecimal {
        val hashedKey = SecurityUtils.hashSensitiveData("balance_$userId")
        val cipherText = securePrefs.getString("${hashedKey}_ct", null)
        val iv = securePrefs.getString("${hashedKey}_iv", null)

        if (cipherText == null || iv == null) return BigDecimal.ZERO

        return try {
            val decrypted = SecurityUtils.decrypt(EncryptedData(cipherText, iv))
            BigDecimal(decrypted)
        } catch (e: Exception) {
            Log.e("SecureStorage", "Failed to decrypt balance", e)
            BigDecimal.ZERO
        }
    }

    fun storePaymentToken(userId: String, token: String) {
        val hashedKey = SecurityUtils.hashSensitiveData("token_$userId")
        val encrypted = SecurityUtils.encrypt(token)
        securePrefs.edit()
            .putString("${hashedKey}_ct", encrypted.cipherText)
            .putString("${hashedKey}_iv", encrypted.iv)
            .apply()
    }

    fun getPaymentToken(userId: String): String? {
        val hashedKey = SecurityUtils.hashSensitiveData("token_$userId")
        val cipherText = securePrefs.getString("${hashedKey}_ct", null)
        val iv = securePrefs.getString("${hashedKey}_iv", null)

        if (cipherText == null || iv == null) return null

        return try {
            SecurityUtils.decrypt(EncryptedData(cipherText, iv))
        } catch (e: Exception) {
            Log.e("SecureStorage", "Failed to decrypt token", e)
            null
        }
    }

    fun clearAllData() {
        securePrefs.edit().clear().apply()
    }

    fun removePaymentToken(userId: String) {
        val hashedKey = SecurityUtils.hashSensitiveData("token_$userId")
        securePrefs.edit()
            .remove("${hashedKey}_ct")
            .remove("${hashedKey}_iv")
            .apply()
    }

    companion object {
        @Volatile
        private var instance: SecureStorage? = null

        fun getInstance(context: Context): SecureStorage {
            return instance ?: synchronized(this) {
                instance ?: SecureStorage(context.applicationContext).also { instance = it }
            }
        }
    }
}

