// ============================================================
// Rate Limiter
// ============================================================

class RateLimiter(
    private val maxRequests: Int = 10,
    private val windowMillis: Long = 60_000L
) {
    private val requestTimestamps = ConcurrentHashMap<String, MutableList<Long>>()

    @Synchronized
    fun allowRequest(userId: String): Boolean {
        val now = System.currentTimeMillis()
        val timestamps = requestTimestamps.getOrPut(userId) { mutableListOf() }

        // Remove expired timestamps
        timestamps.removeAll { now - it > windowMillis }

        return if (timestamps.size < maxRequests) {
            timestamps.add(now)
            true
        } else {
            false
        }
    }

    fun reset(userId: String) {
        requestTimestamps.remove(userId)
    }
}

