object TransactionValidator {

    private const val MAX_TRANSACTION_AMOUNT = 10000.0
    private const val MIN_TRANSACTION_AMOUNT = 0.01
    private val SUPPORTED_CURRENCIES = setOf("USD", "EUR", "GBP", "JPY", "INR", "CAD", "AUD")

    fun validatePurchaseRequest(request: PurchaseRequest): ValidationResult {
        val errors = mutableListOf<String>()

        if (request.productId.isBlank()) {
            errors.add("Product ID cannot be empty")
        }

        if (request.productId.length > 150) {
            errors.add("Product ID exceeds maximum length")
        }

        if (request.amount <= BigDecimal.ZERO) {
            errors.add("Amount must be positive")
        }

        if (request.amount < BigDecimal(MIN_TRANSACTION_AMOUNT)) {
            errors.add("Amount below minimum: $MIN_TRANSACTION_AMOUNT")
        }

        if (request.amount > BigDecimal(MAX_TRANSACTION_AMOUNT)) {
            errors.add("Amount exceeds maximum: $MAX_TRANSACTION_AMOUNT")
        }

        if (request.currency.uppercase() !in SUPPORTED_CURRENCIES) {
            errors.add("Unsupported currency: ${request.currency}")
        }

        if (request.amount.scale() > 2 && request.currency.uppercase() != "JPY") {
            errors.add("Amount has too many decimal places")
        }

        return if (errors.isEmpty()) {
            ValidationResult.Valid
        } else {
            ValidationResult.Invalid(errors)
        }
    }

    fun validateWalletTransaction(amount: BigDecimal, currentBalance: BigDecimal, type: TransactionType): ValidationResult {
        val errors = mutableListOf<String>()

        if (amount <= BigDecimal.ZERO) {
            errors.add("Amount must be positive")
        }

        if (amount > BigDecimal(MAX_TRANSACTION_AMOUNT)) {
            errors.add("Amount exceeds maximum: $MAX_TRANSACTION_AMOUNT")
        }

        if (type == TransactionType.WALLET_DEBIT && currentBalance < amount) {
            errors.add("Insufficient wallet balance")
        }

        return if (errors.isEmpty()) {
            ValidationResult.Valid
        } else {
            ValidationResult.Invalid(errors)
        }
    }

    sealed class ValidationResult {
        object Valid : ValidationResult()
        data class Invalid(val errors: List<String>) : ValidationResult()
    }
}

