class GooglePlayBillingManager(
    private val context: Context,
    private val secureStorage: SecureStorage
) : PurchasesUpdatedListener {

    private var billingClient: BillingClient? = null
    private val _purchaseState = MutableStateFlow<PaymentResult?>(null)
    val purchaseState: StateFlow<PaymentResult?> = _purchaseState.asStateFlow()

    private val pendingTransactions = ConcurrentHashMap<String, Transaction>()
    private val scope = CoroutineScope(Dispatchers.Main + SupervisorJob())

    fun initialize() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()

        startConnection()
    }

    private fun startConnection() {
        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    Log.i("BillingManager", "Billing client connected")
                    scope.launch { processPendingPurchases() }
                } else {
                    Log.w("BillingManager", "Billing setup failed: ${billingResult.responseCode}")
                }
            }

            override fun onBillingServiceDisconnected() {
                Log.w("BillingManager", "Billing service disconnected, retrying...")
                // Retry with exponential backoff
                scope.launch {
                    delay(3000)
                    startConnection()
                }
            }
        })
    }

    suspend fun queryProducts(productIds: List<String>, productType: String = BillingClient.ProductType.INAPP): List<ProductDetails> {
        val client = billingClient ?: throw IllegalStateException("Billing client not initialized")

        val productList = productIds.map { productId ->
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(productType)
                .build()
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        return suspendCancellableCoroutine { continuation ->
            client.queryProductDetailsAsync(params) { billingResult, productDetailsList ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    continuation.resume(productDetailsList) { }
                } else {
                    continuation.resume(emptyList()) { }
                }
            }
        }
    }

    fun launchPurchaseFlow(
        activity: android.app.Activity,
        productDetails: ProductDetails,
        userId: String
    ) {
        val client = billingClient ?: return

        val transactionId = SecurityUtils.generateTransactionId()
        val transaction = Transaction(
            transactionId = transactionId,
            userId = userId,
            type = TransactionType.PURCHASE,
            amount = BigDecimal.ZERO, // Will be updated from purchase
            currency = "USD",
            status = TransactionStatus.PENDING,
            paymentMethod = PaymentMethod.GOOGLE_PLAY,
            productId = productDetails.productId
        )

        pendingTransactions[productDetails.productId] = transaction
        AuditLogger.logTransactionInitiated(transactionId, TransactionType.PURCHASE, userId)

        val productDetailsParamsList = listOf(
            BillingFlowParams.ProductDetailsParams.newBuilder()
                .setProductDetails(productDetails)
                .build()
        )

        val billingFlowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(productDetailsParamsList)
            .setObfuscatedAccountId(SecurityUtils.hashSensitiveData(userId))
            .build()

        client.launchBillingFlow(activity, billingFlowParams)
    }

    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: MutableList<Purchase>?) {
        when (billingResult.responseCode) {
            BillingClient.BillingResponseCode.OK -> {
                purchases?.forEach { purchase ->
                    scope.launch { handlePurchase(purchase) }
                }
            }
            BillingClient.BillingResponseCode.USER_CANCELED -> {
                _purchaseState.value = PaymentResult.Cancelled
                pendingTransactions.values.forEach {
                    AuditLogger.logTransactionCompleted(it.transactionId, TransactionStatus.CANCELLED)
                }
                pendingTransactions.clear()
            }
            else -> {
                val errorMsg = "Purchase failed with code: ${billingResult.responseCode}"
                pendingTransactions.values.forEach { transaction ->
                    AuditLogger.logTransactionFailed(
                        transaction.transactionId,
                        billingResult.responseCode,
                        errorMsg
                    )
                }
                _purchaseState.value = PaymentResult.Error(
                    billingResult.responseCode,
                    "Purchase failed. Please try again."
                )
                pendingTransactions.clear()
            }
        }
    }

    private suspend fun handlePurchase(purchase: Purchase) {
        // Verify purchase signature
        if (!verifyPurchaseSignature(purchase)) {
            AuditLogger.logSecurityEvent(
                "INVALID_SIGNATURE",
                "Purchase signature verification failed for order: ${purchase.orderId}"
            )
            _purchaseState.value = PaymentResult.Error(
                -1,
                "Purchase verification failed. Please contact support."
            )
            return
        }

        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            if (!purchase.isAcknowledged) {
                acknowledgePurchase(purchase)
            }

            val productId = purchase.products.firstOrNull() ?: ""
            val transaction = pendingTransactions.remove(productId)?.copy(
                status = TransactionStatus.COMPLETED
            ) ?: return

            AuditLogger.logTransactionCompleted(transaction.transactionId, TransactionStatus.COMPLETED)
            _purchaseState.value = PaymentResult.Success(transaction)

        } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
            val productId = purchase.products.firstOrNull() ?: ""
            val transaction = pendingTransactions[productId]?.copy(
                status = TransactionStatus.PROCESSING
            ) ?: return

            AuditLogger.logTransactionCompleted(transaction.transactionId, TransactionStatus.PROCESSING)
            _purchaseState.value = PaymentResult.Pending(transaction)
        }
    }

    private fun verifyPurchaseSignature(purchase: Purchase): Boolean {
        // In production, verify the purchase signature server-side
        // This is a critical security check
        if (purchase.signature.isBlank()) {
            return false
        }
        // TODO: Implement server-side verification
        // Send purchase.originalJson and purchase.signature to your backend
        // Backend verifies using your Google Play public key
        return purchase.purchaseState == Purchase.PurchaseState.PURCHASED ||
                purchase.purchaseState == Purchase.PurchaseState.PENDING
    }

    private suspend fun acknowledgePurchase(purchase: Purchase) {
        val client = billingClient ?: return

        val acknowledgePurchaseParams = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        withContext(Dispatchers.IO) {
            client.acknowledgePurchase(acknowledgePurchaseParams) { billingResult ->
                if (billingResult.responseCode != BillingClient.BillingResponseCode.OK) {
                    Log.w("BillingManager", "Acknowledge failed: ${billingResult.responseCode}")
                }
            }
        }
    }

    private suspend fun processPendingPurchases() {
        val client = billingClient ?: return

        val params = QueryPurchasesParams.newBuilder()
            .setProductType(BillingClient.ProductType.INAPP)
            .build()

        client.queryPurchasesAsync(params) { billingResult, purchasesList ->
            if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                purchasesList.forEach { purchase ->
                    if (!purchase.isAcknowledged && purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
                        scope.launch { handlePurchase(purchase) }
                    }
                }
            }
        }
    }

    fun destroy() {
        scope.cancel()
        billingClient?.endConnection()
        billingClient = null
        pendingTransactions.clear()
    }
}

