class WalletManager(
    private val context: Context,
    private val secureStorage: SecureStorage
) {
    private val rateLimiter = RateLimiter(maxRequests = 20, windowMillis = 60_000L)
    private val transactionLocks = ConcurrentHashMap<String, Any>()

    private val _walletState = MutableStateFlow<WalletInfo?>(null)
    val walletState: StateFlow<WalletInfo?> = _walletState.asStateFlow()

    private val _transactionHistory = MutableStateFlow<List<Transaction>>(emptyList())
    val transactionHistory: StateFlow<List<Transaction>> = _transactionHistory.asStateFlow()

    fun loadWallet(userId: String, currency: String = "USD") {
        val balance = secureStorage.getWalletBalance(userId)
        _walletState.value = WalletInfo(
            userId = userId,
            balance = balance,
            currency = currency
        )
    }

    @WorkerThread
    suspend fun creditWallet(
        userId: String,
        amount: BigDecimal,
        currency: String = "USD",
        description: String = ""
    ): WalletResult = withContext(Dispatchers.IO) {
        val sanitizedDescription = SecurityUtils.sanitizeInput(description)

        if (!rateLimiter.allowRequest(userId)) {
            AuditLogger.logSecurityEvent("RATE_LIMIT", "User rate limited for wallet credit")
            return@withContext WalletResult.Error(429, "Too many requests. Please try again later.")
        }

        val lock = transactionLocks.getOrPut(userId) { Any() }

        synchronized(lock) {
            val currentBalance = secureStorage.getWalletBalance(userId)

            val validation = TransactionValidator.validateWalletTransaction(
                amount, currentBalance, TransactionType.WALLET_CREDIT
            )

            if (validation is TransactionValidator.ValidationResult.Invalid) {
                return@withContext WalletResult.Error(400, validation.errors.joinToString("; "))
            }

            val transactionId = SecurityUtils.generateTransactionId()
            AuditLogger.logTransactionInitiated(transactionId, TransactionType.WALLET_CREDIT, userId)

            val newBalance = currentBalance.add(amount)
            secureStorage.storeWalletBalance(userId, newBalance)

            val transaction = Transaction(
                transactionId = transactionId,
                userId = userId,
                type = TransactionType.WALLET_CREDIT,
                amount = amount,
                currency = currency,
                status = TransactionStatus.COMPLETED,
                paymentMethod = PaymentMethod.WALLET,
                description = sanitizedDescription
            )

            val walletInfo = WalletInfo(userId, newBalance, currency)
            _walletState.value = walletInfo

            addToHistory(transaction)
            AuditLogger.logWalletOperation(transactionId, TransactionType.WALLET_CREDIT)
            AuditLogger.logTransactionCompleted(transactionId, TransactionStatus.COMPLETED)

            return@withContext WalletResult.Success(walletInfo, transaction)
        }
    }

    @WorkerThread
    suspend fun debitWallet(
        userId: String,
        amount: BigDecimal,
        currency: String = "USD",
        description: String = "",
        productId: String? = null
    ): WalletResult = withContext(Dispatchers.IO) {
        val sanitizedDescription = SecurityUtils.sanitizeInput(description)

        if (!rateLimiter.allowRequest(userId)) {
            AuditLogger.logSecurityEvent("RATE_LIMIT", "User rate limited for wallet debit")
            return@withContext WalletResult.Error(429, "Too many requests. Please try again later.")
        }

        val lock = transactionLocks.getOrPut(userId) { Any() }

        synchronized(lock) {
            val currentBalance = secureStorage.getWalletBalance(userId)

            val validation = TransactionValidator.validateWalletTransaction(
                amount, currentBalance, TransactionType.WALLET_DEBIT
            )

            if (validation is TransactionValidator.ValidationResult.Invalid) {
                if (currentBalance < amount) {
                    return@withContext WalletResult.InsufficientFunds(currentBalance, amount)
                }
                return@withContext WalletResult.Error(400, validation.errors.joinToString("; "))
            }

            val transactionId = SecurityUtils.generateTransactionId()
            AuditLogger.logTransactionInitiated(transactionId, TransactionType.WALLET_DEBIT, userId)

            val newBalance = currentBalance.subtract(amount)
            secureStorage.storeWalletBalance(userId, newBalance)

            val transaction = Transaction(
                transactionId = transactionId,
                userId = userId,
                type = TransactionType.WALLET_DEBIT,
                amount = amount,
                currency = currency,
                status = TransactionStatus.COMPLETED,
                paymentMethod = PaymentMethod.WALLET,
                productId = productId,
                description = sanitizedDescription
            )

            val walletInfo = WalletInfo(userId, newBalance, currency)
            _walletState.value = walletInfo

            addToHistory(transaction)
            AuditLogger.logWalletOperation(transactionId, TransactionType.WALLET_DEBIT)
            AuditLogger.logTransactionCompleted(transactionId, TransactionStatus.COMPLETED)

            return@withContext WalletResult.Success(walletInfo, transaction)
        }
    }

    @WorkerThread
    suspend fun processRefund(
        userId: String,
        originalTransactionId: String,
        amount: BigDecimal,
        currency: String = "USD"
    ): WalletResult = withContext(Dispatchers.IO) {
        if (!rateLimiter.allowRequest(userId)) {
            AuditLogger.logSecurityEvent("RATE_LIMIT", "User rate limited for refund")
            return@withContext WalletResult.Error(429, "Too many requests. Please try again later.")
        }

        val lock = transactionLocks.getOrPut(userId) { Any() }

        synchronized(lock) {
            val currentBalance = secureStorage.getWalletBalance(userId)

            val transactionId = SecurityUtils.generateTransactionId()
            AuditLogger.logTransactionInitiated(transactionId, TransactionType.REFUND, userId)

            val newBalance = currentBalance.add(amount)
            secureStorage.storeWalletBalance(userId, newBalance)

            val transaction = Transaction(
                transactionId = transactionId,
                userId = userId,
                type = TransactionType.REFUND,
                amount = amount,
                currency = currency,
                status = TransactionStatus.COMPLETED,
                paymentMethod = PaymentMethod.WALLET,
                description = "Refund for transaction: $originalTransactionId",
                metadata = mapOf("originalTransactionId" to originalTransactionId)
            )

            val walletInfo = WalletInfo(userId, newBalance, currency)
            _walletState.value = walletInfo

            addToHistory(transaction)
            AuditLogger.logWalletOperation(transactionId, TransactionType.REFUND)
            AuditLogger.logTransactionCompleted(transactionId, TransactionStatus.COMPLETED)

            return@withContext WalletResult.Success(walletInfo, transaction)
        }
    }

    fun getBalance(userId: String): BigDecimal {
        return secureStorage.getWalletBalance(userId)
    }

    private fun addToHistory(transaction: Transaction) {
        val current = _transactionHistory.value.toMutableList()
        current.add(0, transaction)
        // Keep only last 100 transactions in memory
        if (current.size > 100) {
            _transactionHistory.value = current.take(100)
        } else {
            _transactionHistory.value = current
        }
    }
}

// ============================================================
// Payment Processor (Orchestrator)
// ============================================================

class PaymentProcessor(
    private val context: Context
) {
    private val secureStorage = SecureStorage.getInstance(context)
    val billingManager = GooglePlayBillingManager(context, secureStorage)
    val walletManager = WalletManager(context, secureStorage)

    private val rateLimiter = RateLimiter(maxRequests = 5, windowMillis = 30_000L)
    private val processedIdempotencyKeys = ConcurrentHashMap<String, PaymentResult>()

    fun initialize() {
        billingManager.initialize()
    }

    suspend fun processPurchase(
        userId: String,
        request: PurchaseRequest
    ): PaymentResult {
        // Idempotency check
        processedIdempotencyKeys[request.idempotencyKey]?.let { return it }

        // Rate limiting
        if (!rateLimiter.allowRequest(userId)) {
            AuditLogger.logSecurityEvent("RATE_LIMIT", "User rate limited for purchase")
            return PaymentResult.Error(429, "Too many requests. Please try again later.")
        }

        // Input validation
        val validation = TransactionValidator.validatePurchaseRequest(request)
        if (validation is TransactionValidator.ValidationResult.Invalid) {
            return PaymentResult.Error(400, validation.errors.joinToString("; "))
        }

        val result = when (request.paymentMethod) {
            PaymentMethod.WALLET -> processWalletPurchase(userId, request)
            PaymentMethod.GOOGLE_PLAY -> {
                // Google Play purchases are handled via launchPurchaseFlow
                PaymentResult.Error(400, "Use launchGooglePlayPurchase for Google Play purchases")
            }
            PaymentMethod.CREDIT_CARD_TOKEN -> {
                // Tokenized card payments should go through a PCI-compliant payment gateway
                processTokenizedPayment(userId, request)
            }
        }

        // Store for idempotency
        processedIdempotencyKeys[request.idempotencyKey] = result

        // Clean up old idempotency keys periodically
        if (processedIdempotencyKeys.size > 1000) {
            val keysToRemove = processedIdempotencyKeys.keys.take(500)
            keysToRemove.forEach { processedIdempotencyKeys.remove(it) }
        }

        return result
    }

    private suspend fun processWalletPurchase(userId: String, request: PurchaseRequest): PaymentResult {
        val walletResult = walletManager.debitWallet(
            userId = userId,
            amount = request.amount,
            currency = request.currency,
            description = "Purchase: ${SecurityUtils.sanitizeInput(request.productId)}",
            productId = request.productId
        )

        return when (walletResult) {
            is WalletResult.Success -> PaymentResult.Success(walletResult.transaction)
            is WalletResult.InsufficientFunds -> PaymentResult.Error(
                402,
                "Insufficient wallet balance"
            )
            is WalletResult.Error -> PaymentResult.Error(walletResult.code, walletResult.message)
        }
    }

    private suspend fun processTokenizedPayment(userId: String, request: PurchaseRequest): PaymentResult {
        val token = secureStorage.getPaymentToken(userId)
            ?: return PaymentResult.Error(400, "No payment method on file")

        val transactionId = SecurityUtils.generateTransactionId()
        AuditLogger.logTransactionInitiated(transactionId, TransactionType.PURCHASE, userId)

        // In production, send tokenized request to payment gateway (Stripe, Braintree, etc.)
        // Never handle raw card numbers - only tokens
        // The actual charge happens server-side

        val transaction = Transaction(
            transactionId = transactionId,
            userId = userId,
            type = TransactionType.PURCHASE,
            amount = request.amount,
            currency = request.currency,
            status = TransactionStatus.PROCESSING,
            paymentMethod = PaymentMethod.CREDIT_CARD_TOKEN,
            productId = request.productId,
            description = "Tokenized payment for ${SecurityUtils.sanitizeInput(request.productId)}"
        )

        AuditLogger.logTransactionCompleted(transactionId, TransactionStatus.PROCESSING)
        return PaymentResult.Pending(transaction)
    }

    fun storePaymentToken(userId: String, token: String) {
        // Validate token format before storing
        val sanitizedToken = SecurityUtils.sanitizeInput(token)
        if (sanitizedToken.isBlank() || sanitizedToken.length > 500) {
            throw IllegalArgumentException("Invalid payment token")
        }
        secureStorage.storePaymentToken(userId, sanitizedToken)
    }

    fun removePaymentToken(userId: String) {
        secureStorage.removePaymentToken(userId)
    }

    fun destroy() {
        billingManager.destroy()
    }
}

// ============================================================
// ViewModel
// ============================================================

class PaymentViewModel(
    private val paymentProcessor: PaymentProcessor
) : ViewModel() {

    private val _uiState = MutableLiveData<PaymentUiState>()
    val uiState: LiveData<PaymentUiState> = _uiState

    val walletState = paymentProcessor.walletManager.walletState
    val transactionHistory = paymentProcessor.walletManager.transactionHistory
    val purchaseState = paymentProcessor.billingManager.purchaseState

    init {
        paymentProcessor.initialize()
    }

    fun loadWallet(userId: String) {
        paymentProcessor.walletManager.loadWallet(userId)
    }

    fun purchaseWithWallet(userId: String, productId: String, amount: BigDecimal, currency: String = "USD") {
        _uiState.value = PaymentUiState.Loading

        viewModelScope.launch {
            try {
                val request = PurchaseRequest(
                    productId = productId,
                    amount = amount,
                    currency = currency,
                    paymentMethod = PaymentMethod.WALLET
                )

                when (val result = paymentProcessor.processPurchase(userId, request)) {
                    is PaymentResult.Success -> {
                        _uiState.value = PaymentUiState.PurchaseSuccess(result.transaction)
                    }
                    is PaymentResult.Error -> {
                        _uiState.value = PaymentUiState.Error(result.message)
                    }
                    is PaymentResult.Pending -> {
                        _uiState.value = PaymentUiState.PurchasePending(result.transaction)
                    }
                    PaymentResult.Cancelled -> {
                        _uiState.value = PaymentUiState.Cancelled
                    }
                }
            } catch (e: Exception) {
                _uiState.value = PaymentUiState.Error("An unexpected error occurred. Please try again.")
                AuditLogger.logSecurityEvent("UNEXPECTED_ERROR", "Purchase failed with exception")
            }
        }
    }

    fun creditWallet(userId: String, amount: BigDecimal, description: String = "") {
        _uiState.value = PaymentUiState.Loading

        viewModelScope.launch {
            try {
                when (val result = paymentProcessor.walletManager.creditWallet(userId, amount, description = description)) {
                    is WalletResult.Success -> {
                        _uiState.value = PaymentUiState.WalletUpdated(result.walletInfo)
                    }
                    is WalletResult.Error -> {
                        _uiState.value = PaymentUiState.Error(result.message)
                    }
                    is WalletResult.InsufficientFunds -> {
                        _uiState.value = PaymentUiState.Error("Insufficient funds")
                    }
                }
            } catch (e: Exception) {
                _uiState.value = PaymentUiState.Error("An unexpected error occurred. Please try again.")
            }
        }
    }

    fun requestRefund(userId: String, originalTransactionId: String, amount: BigDecimal) {
        _uiState.value = PaymentUiState.Loading

        viewModelScope.launch {
            try {
                when (val result = paymentProcessor.walletManager.processRefund(userId, originalTransactionId, amount)) {
                    is WalletResult.Success -> {
                        _uiState.value = PaymentUiState.RefundProcessed(result.transaction)
                    }
                    is WalletResult.Error -> {
                        _uiState.value = PaymentUiState.Error(result.message)
                    }
                    is WalletResult.InsufficientFunds -> {
                        _uiState.value = PaymentUiState.Error("Refund processing error")
                    }
                }
            } catch (e: Exception) {
                _uiState.value = PaymentUiState.Error("An unexpected error occurred. Please try again.")
            }
        }
    }

    override fun onCleared() {
        super.onCleared()
        paymentProcessor.destroy()
    }
}

sealed class PaymentUiState {
    object Loading : PaymentUiState()
    object Cancelled : PaymentUiState()
    data class PurchaseSuccess(val transaction: Transaction) : PaymentUiState()
    data class PurchasePending(val transaction: Transaction) : PaymentUiState()
    data class WalletUpdated(val walletInfo: WalletInfo) : PaymentUiState()
    data class RefundProcessed(val transaction: Transaction) : PaymentUiState()
    data class Error(val message: String) : PaymentUiState()
}

// ============================================================
// Device Compatibility Helper
// ============================================================

object DeviceCompatibility {
    fun isGooglePlayAvailable(context: Context): Boolean {
        return try {
            context.packageManager.getPackageInfo("com.android.vending", 0)
            true
        } catch (e: Exception) {
            false
        }
    }

    fun supportsStrongBoxKeyStore(): Boolean {
        return Build.VERSION.SDK_INT >= Build.VERSION_CODES.P
    }

    fun getSecurityLevel(): String {
        return when {
            Build.VERSION.SDK_INT >= Build.VERSION_CODES.P -> "HIGH"
            Build.VERSION.SDK_INT >= Build.VERSION_CODES.M -> "MEDIUM"
            else -> "BASIC"
        }
    }

    fun getAvailablePaymentMethods(context: Context): List<PaymentMethod> {
        val methods = mutableListOf(PaymentMethod.WALLET)

        if (isGooglePlayAvailable(context)) {
            methods.add(PaymentMethod.GOOGLE_PLAY)
        }

        methods.add(PaymentMethod.CREDIT_CARD_TOKEN)

        return methods
    }
}